		if strings.Contains(s.SQL, "DROP COLUMN") && strings.Contains(s.SQL, "Name") {
			found = true
		}
	}
	if !found {
		t.Error("expected ALTER TABLE ... DROP COLUMN Name statement")
		for _, s := range stmts {
			t.Logf("  %s: %s", s.Kind, s.SQL)
